Future<_SettingsBootstrapData> _loadSettingsBootstrapData() async {
  final result = await _loadAppSettingsBootstrapUseCase.execute();
  return _SettingsBootstrapData(
    initialVoiceAlertEnabled: result.initialVoiceAlertEnabled,
    isDriver: result.isDriver,
    subscriptionStatus: result.subscriptionStatus,
    trialDaysLeft: result.trialDaysLeft,
    initialShowPhoneToPassengers: result.initialShowPhoneToPassengers,
  );
}

Future<_DriverProfileSetupBootstrapData> _loadDriverProfileSetupBootstrapData(
  User? user,
) async {
  final result = await _loadDriverProfileSetupBootstrapUseCase.execute(
    DriverProfileSetupBootstrapSeed(
      fallbackName: _resolveDisplayName(user),
      userId: user?.uid,
      isAnonymous: user?.isAnonymous ?? false,
      fallbackPhone: user?.phoneNumber,
      fallbackPhotoUrl: user?.photoURL,
    ),
  );
  return _DriverProfileSetupBootstrapData(
    name: result.name,
    phone: result.phone,
    plate: result.plate,
    showPhoneToPassengers: result.showPhoneToPassengers,
    photoUrl: result.photoUrl,
    photoPath: result.photoPath,
  );
}

Future<_ProfileEditBootstrapData> _loadProfileEditBootstrapData(
  User? user,
) async {
  final result = await _loadProfileEditBootstrapUseCase.execute(
    ProfileEditBootstrapSeed(
      fallbackDisplayName: _resolveDisplayName(user),
      userId: user?.uid,
      isAnonymous: user?.isAnonymous ?? false,
      fallbackPhone: user?.phoneNumber,
      fallbackPhotoUrl: user?.photoURL,
    ),
  );
  return _ProfileEditBootstrapData(
    role: result.role,
    displayName: result.displayName,
    phone: result.phone,
    photoUrl: result.photoUrl,
    photoPath: result.photoPath,
  );
}

Future<_DriverHomeBootstrapData> _loadDriverHomeBootstrapData() async {
  final user = _authCredentialGateway.currentUser;
  if (user == null || user.isAnonymous) {
    return const _DriverHomeBootstrapData();
  }
  final orchestrator =
      LoadDriverHomeBootstrapOrchestratorUseCase<DriverTripListItem>(
    loadHeaderBootstrap: _loadDriverHomeHeaderBootstrapUseCase.execute,
    loadMyTrips: _loadDriverMyTripsItems,
    loadSubscriptionSnapshot: _loadDriverSubscriptionSnapshotUseCase.execute,
    loadRouteSection: _loadDriverHomeRouteSectionUseCase.execute,
    trackRouteSectionPerf: ({
      required durationMs,
      required outcome,
      required routeCount,
    }) {
      _mobileTelemetry.trackPerf(
        eventName: MobileEventNames.routeListLoad,
        durationMs: durationMs,
        attributes: <String, Object?>{
          'outcome': outcome,
          'routeCount': routeCount,
        },
      );
    },
  );
  final orchestrated = await orchestrator.execute(
    DriverHomeBootstrapOrchestratorSeed(
      userId: user.uid,
      fallbackDisplayName: _resolveDisplayName(user),
      fallbackPhotoUrl: user.photoURL,
    ),
  );
  if (!orchestrated.isDriver) {
    return const _DriverHomeBootstrapData();
  }
  final driverDisplayName = orchestrated.driverDisplayName;
  final driverPhotoUrl = orchestrated.driverPhotoUrl;
  final myTrips = orchestrated.myTrips;
  final subscription = _DriverSubscriptionSnapshot(
    status: orchestrated.subscription.status,
    trialDaysLeft: orchestrated.subscription.trialDaysLeft,
  );
  final routeSection = orchestrated.routeSection;
  if (routeSection == null) {
    return _DriverHomeBootstrapData(
      myTrips: myTrips,
      driverDisplayName: driverDisplayName,
      driverPhotoUrl: driverPhotoUrl,
      subscriptionStatus: subscription.status,
      trialDaysLeft: subscription.trialDaysLeft,
    );
  }
  final stops = routeSection.stops
      .map(
        (stop) => DriverMapStopInfo(
          stopId: stop.stopId,
          name: stop.name,
          order: stop.order,
          passengersWaiting: stop.passengersWaiting,
        ),
      )
      .toList(growable: false);
  return _DriverHomeBootstrapData(
    routeName: routeSection.routeName,
    stops: stops,
    myTrips: myTrips,
    driverDisplayName: driverDisplayName,
    driverPhotoUrl: driverPhotoUrl,
    queuedPassengerCount: routeSection.queuedPassengerCount,
    subscriptionStatus: subscription.status,
    trialDaysLeft: subscription.trialDaysLeft,
  );
}

Future<_DriverTripCompletedBootstrapData>
    _loadDriverTripCompletedBootstrapData({
  required String? routeId,
  required String? tripId,
}) async {
  final rawData = await _loadDriverTripCompletedBootstrapRawUseCase.execute(
    routeId: _nullableParam(routeId),
    tripId: _nullableParam(tripId),
  );
  if (rawData == null) {
    return const _DriverTripCompletedBootstrapData();
  }
  final composed = _composeDriverTripCompletedBootstrapUseCase.execute(rawData);
  final stopItems = _buildTripCompletedStopItems(
    stops: composed.stops,
    startedAtUtc: composed.startedAtUtc,
    totalDurationMinutes: composed.totalDurationMinutes,
  );
  return _DriverTripCompletedBootstrapData(
    totalDistanceKm: composed.totalDistanceKm,
    totalDurationMinutes: composed.totalDurationMinutes,
    totalPassengers: composed.totalPassengers,
    stops: stopItems,
  );
}

