      );
    }
    stops.sort((left, right) => left.order.compareTo(right.order));

    final passengers = <DriverTripDetailPassengerItem>[];
    for (final passengerRow in rawData.passengerRows) {
      final data = passengerRow.passengerData;
      final name = _nullableParam(data['name'] as String?) ?? 'Personel';
      passengers.add(
        DriverTripDetailPassengerItem(
          passengerId: passengerRow.passengerId,
          name: name,
          boardingArea: _nullableParam(data['boardingArea'] as String?),
        ),
      );
    }
    passengers.sort((left, right) => left.name.compareTo(right.name));

    return DriverTripDetailData(
      routeId: normalizedRouteId,
      routeName: routeName,
      startAddress: startAddress,
      endAddress: endAddress,
      startPoint: startPoint,
      endPoint: endPoint,
      status: _mapDriverTripCardStatus(
          _nullableParam(tripData?['status'] as String?)),
      stops: stops,
      passengers: passengers,
      tripId: normalizedTripId,
      srvCode: _nullableParam(routeData['srvCode'] as String?),
      scheduledTimeLabel: _nullableParam(routeData['scheduledTime'] as String?),
      routePolylineEncoded:
          _nullableParam(routeData['routePolyline'] as String?),
      tripStartedAtUtc: tripData == null
          ? null
          : _parseTripHistoryDate(tripData['startedAt']),
      tripEndedAtUtc:
          tripData == null ? null : _parseTripHistoryDate(tripData['endedAt']),
    );
  } catch (_) {
    return _buildDriverTripDetailFromRecentStub(
      routeId: normalizedRouteId,
      tripId: normalizedTripId,
    );
  }
}

DriverTripCardStatus _mapDriverTripCardStatus(String? rawStatus) {
  final normalized = rawStatus?.trim().toLowerCase();
  return switch (normalized) {
    'active' => DriverTripCardStatus.live,
    'completed' => DriverTripCardStatus.completed,
    'abandoned' || 'cancelled' || 'canceled' => DriverTripCardStatus.canceled,
    _ => DriverTripCardStatus.planned,
  };
}

DriverTripGeoPoint _parseDriverTripGeoPoint(Object? raw) {
  if (raw is Map<String, dynamic>) {
    return DriverTripGeoPoint(
      lat: (raw['lat'] as num?)?.toDouble() ?? 41.0082,
      lng: (raw['lng'] as num?)?.toDouble() ?? 28.9784,
    );
  }
  if (raw is Map) {
    final lat = raw['lat'];
    final lng = raw['lng'];
    return DriverTripGeoPoint(
      lat: (lat is num) ? lat.toDouble() : 41.0082,
      lng: (lng is num) ? lng.toDouble() : 28.9784,
    );
  }
  return const DriverTripGeoPoint(lat: 41.0082, lng: 28.9784);
}

DateTime? _parseScheduledTimeAsTodayLocal(String? raw) {
  final normalized = raw?.trim();
  if (normalized == null || normalized.isEmpty) {
    return null;
  }
  final match = RegExp(r'^(\d{1,2}):(\d{2})$').firstMatch(normalized);
  if (match == null) {
    return null;
  }
  final hour = int.tryParse(match.group(1) ?? '');
  final minute = int.tryParse(match.group(2) ?? '');
  if (hour == null || minute == null) {
    return null;
  }
  if (hour < 0 || hour > 23 || minute < 0 || minute > 59) {
    return null;
  }
  final now = DateTime.now();
  return DateTime(now.year, now.month, now.day, hour, minute);
}

Future<_DriverSubscriptionSnapshot>
    _resolveCurrentDriverSubscriptionSnapshot() async {
  final snapshot =
      await _loadCurrentAuthDriverSubscriptionSnapshotUseCase.execute();
  return _DriverSubscriptionSnapshot(
    status: snapshot.status,
    trialDaysLeft: snapshot.trialDaysLeft,
  );
}
